function initializeAdminApp(): App {
  const appName = 'firebase-admin-app-[StakIt]';
  const existingApp = getApps().find(app => app.name === appName);
  if (existingApp) {
    return existingApp;
  }
  const serviceAccount = {
      ...serviceAccountKey,
      private_key: serviceAccountKey.private_key.replace(/\\n/g, '\n'),
  };
  return initializeApp({ credential: cert(serviceAccount) }, appName);
}

const contactFormSchema = z.object({
  name: z.string().min(1, 'Name is required.'),
  email: z.string().email('Invalid email address.'),
  message: z.string().min(10, 'Message must be at least 10 characters long.'),
});

export async function submitContactForm(
    formData: z.infer<typeof contactFormSchema>
): Promise<{ success: true } | { success: false; error: string }> {
     try {
        const adminApp = initializeAdminApp();
        const adminFirestore = getFirestore(adminApp);
        
        const validatedData = contactFormSchema.parse(formData);

        const messageData: ContactMessage = {
            ...validatedData,
            status: 'New',
            submittedDate: new Date().toISOString(),
        };

        await adminFirestore.collection('contactMessages').add(messageData);

        revalidatePath('/admin');
        
        return { success: true };

     } catch (error: any) {
        console.error(`Error submitting contact form:`, error);
        if (error instanceof z.ZodError) {
            return { success: false, error: error.errors.map(e => e.message).join(', ') };
        }
        return { success: false, error: error.message || 'An unknown error occurred.' };
     }
}
